CREATE TYPE "AssessmentType" AS ENUM ('RETIREMENT_READINESS','SUITABILITY','VISA_ELIGIBILITY','AFFORDABILITY');
CREATE TYPE "ContentType" AS ENUM ('BLOG','ARTICLE','AREA_GUIDE','HOSPITAL_GUIDE','DEVELOPER_REVIEW','MARKET_REPORT','VISA_UPDATE','RETIREMENT_GUIDE','LANDING_PAGE');
CREATE TYPE "RevenueServiceLine" AS ENUM ('PROPERTY_COMMISSION','DEVELOPER_REFERRAL','VISA_SERVICE','RELOCATION','HEALTHCARE_REFERRAL','INSURANCE_REFERRAL','PROPERTY_MANAGEMENT','RENTAL_MANAGEMENT','CONSULTING');
CREATE TYPE "RevenueStatus" AS ENUM ('PIPELINE','EXPECTED','CLOSED','LOST');
CREATE TYPE "PaymentStatus" AS ENUM ('PENDING','INVOICED','PAID','OVERDUE','CANCELLED');
CREATE TYPE "PartnerType" AS ENUM ('DEVELOPER','LAW_FIRM','VISA_AGENT','HOSPITAL','INSURANCE_PROVIDER','PROPERTY_MANAGER','TAX_ADVISOR','BANK');
CREATE TYPE "ReferralType" AS ENUM ('CLIENT','PARTNER','ADVISOR');
CREATE TYPE "BrandType" AS ENUM ('RETIREMENT_ADVISORY','VISA_ADVISORY','PROPERTY_ADVISORY','HEALTHCARE_CONCIERGE','WEALTH_PRESERVATION','ESTATE_PLANNING');
CREATE TABLE brands (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, type "BrandType" NOT NULL, domain TEXT, country TEXT, language TEXT NOT NULL DEFAULT 'en', currency TEXT NOT NULL DEFAULT 'THB', created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE assessment_results (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID REFERENCES retirees(id) ON DELETE CASCADE, type "AssessmentType" NOT NULL, email TEXT, name TEXT, country TEXT, inputs JSONB NOT NULL, score INT NOT NULL, recommendations JSONB NOT NULL, created_lead BOOLEAN NOT NULL DEFAULT false, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE lead_magnets (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), slug TEXT UNIQUE NOT NULL, title TEXT NOT NULL, description TEXT, resource_url TEXT, target_market TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE lead_magnet_downloads (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), lead_magnet_id UUID NOT NULL REFERENCES lead_magnets(id) ON DELETE CASCADE, retiree_id UUID REFERENCES retirees(id) ON DELETE SET NULL, name TEXT NOT NULL, email TEXT NOT NULL, country TEXT, timeline TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE content_items (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), type "ContentType" NOT NULL, slug TEXT UNIQUE NOT NULL, title TEXT NOT NULL, excerpt TEXT, body TEXT NOT NULL, seo_title TEXT, seo_description TEXT, keywords TEXT[] NOT NULL DEFAULT '{}', region TEXT, language TEXT NOT NULL DEFAULT 'en', brand_id UUID REFERENCES brands(id) ON DELETE SET NULL, published_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE landing_pages (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), slug TEXT UNIQUE NOT NULL, headline TEXT NOT NULL, region TEXT, property_type TEXT, seo_title TEXT, seo_description TEXT, faq JSONB, cta_text TEXT, calculator_type "AssessmentType", brand_id UUID REFERENCES brands(id) ON DELETE SET NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE ai_generated_reports (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID REFERENCES retirees(id) ON DELETE CASCADE, report_type "ReportType" NOT NULL, title TEXT NOT NULL, content JSONB NOT NULL, pdf_url TEXT, excel_url TEXT, portal_published BOOLEAN NOT NULL DEFAULT false, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE client_proposals (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID NOT NULL REFERENCES retirees(id) ON DELETE CASCADE, title TEXT NOT NULL, editable_content JSONB NOT NULL, pdf_url TEXT, status TEXT NOT NULL DEFAULT 'draft', created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE revenue_opportunities (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID REFERENCES retirees(id) ON DELETE SET NULL, property_id UUID REFERENCES properties(id) ON DELETE SET NULL, service_line "RevenueServiceLine" NOT NULL, expected_revenue DECIMAL NOT NULL, closed_revenue DECIMAL, status "RevenueStatus" NOT NULL DEFAULT 'PIPELINE', region TEXT, currency TEXT NOT NULL DEFAULT 'THB', expected_close_date TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE commissions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), revenue_opportunity_id UUID REFERENCES revenue_opportunities(id) ON DELETE SET NULL, developer_id UUID REFERENCES developers(id) ON DELETE SET NULL, property_id UUID REFERENCES properties(id) ON DELETE SET NULL, retiree_id UUID REFERENCES retirees(id) ON DELETE SET NULL, advisor_id UUID, source TEXT, commission_percent DECIMAL, commission_amount DECIMAL NOT NULL, payment_status "PaymentStatus" NOT NULL DEFAULT 'PENDING', payment_date TIMESTAMPTZ);
CREATE TABLE partners (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, type "PartnerType" NOT NULL, country TEXT, region TEXT, contact_name TEXT, email TEXT, phone TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE partner_referrals (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), partner_id UUID NOT NULL REFERENCES partners(id) ON DELETE CASCADE, retiree_id UUID REFERENCES retirees(id) ON DELETE SET NULL, revenue_generated DECIMAL, status TEXT NOT NULL DEFAULT 'new', created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE advisor_assets (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID REFERENCES retirees(id) ON DELETE CASCADE, asset_type TEXT NOT NULL, title TEXT NOT NULL, content TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE client_journey_events (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), retiree_id UUID NOT NULL REFERENCES retirees(id) ON DELETE CASCADE, stage TEXT NOT NULL, entered_at TIMESTAMPTZ NOT NULL DEFAULT now(), exited_at TIMESTAMPTZ, revenue_at_stage DECIMAL);
CREATE TABLE marketing_metrics (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), date TIMESTAMPTZ NOT NULL, source TEXT NOT NULL, campaign TEXT, landing_page TEXT, visitors INT NOT NULL DEFAULT 0, leads INT NOT NULL DEFAULT 0, conversions INT NOT NULL DEFAULT 0, spend DECIMAL DEFAULT 0, revenue DECIMAL DEFAULT 0, region TEXT);
CREATE TABLE email_campaigns (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, sequence_type TEXT NOT NULL, audience TEXT, status TEXT NOT NULL DEFAULT 'draft', revenue_generated DECIMAL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE email_sequence_steps (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), campaign_id UUID NOT NULL REFERENCES email_campaigns(id) ON DELETE CASCADE, step_number INT NOT NULL, subject TEXT NOT NULL, body TEXT NOT NULL, delay_days INT NOT NULL DEFAULT 0, UNIQUE(campaign_id, step_number));
CREATE TABLE email_events (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), campaign_id UUID REFERENCES email_campaigns(id) ON DELETE SET NULL, retiree_id UUID REFERENCES retirees(id) ON DELETE SET NULL, event_type TEXT NOT NULL, revenue DECIMAL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE referrals (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), type "ReferralType" NOT NULL, referrer_name TEXT NOT NULL, referrer_email TEXT, referred_retiree_id UUID REFERENCES retirees(id) ON DELETE SET NULL, revenue DECIMAL DEFAULT 0, status TEXT NOT NULL DEFAULT 'submitted', created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX assessment_results_type_score_idx ON assessment_results(type, score); CREATE INDEX assessment_results_email_idx ON assessment_results(email); CREATE INDEX lead_magnet_downloads_email_idx ON lead_magnet_downloads(email); CREATE INDEX content_items_type_region_published_at_idx ON content_items(type, region, published_at); CREATE INDEX landing_pages_region_property_type_idx ON landing_pages(region, property_type); CREATE INDEX revenue_opportunities_service_line_status_idx ON revenue_opportunities(service_line, status); CREATE INDEX revenue_opportunities_region_status_idx ON revenue_opportunities(region, status); CREATE INDEX commissions_payment_status_idx ON commissions(payment_status); CREATE INDEX partners_type_region_idx ON partners(type, region); CREATE INDEX marketing_metrics_date_source_idx ON marketing_metrics(date, source); CREATE INDEX referrals_type_status_idx ON referrals(type, status);
